import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Phone, MessageSquare } from 'lucide-react';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'Home', path: '/', id: 'nav-home' },
    { name: 'Collections', path: '/catalog', id: 'nav-catalog' },
    { name: 'Contact Us', path: '/contact', id: 'nav-contact' },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="sticky top-0 z-40 bg-cream/90 backdrop-blur-md border-b border-borderSubtle">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          {/* Logo Section */}
          <div className="flex-shrink-0 flex flex-col justify-center">
            <Link to="/" className="flex flex-col" data-testid="logo-link">
              <span className="font-serif text-2xl md:text-3xl font-bold tracking-wide text-espresso leading-none">
                V.K. Furniture
              </span>
              <span className="font-devanagari text-sm text-brass mt-0.5 tracking-wider font-semibold">
                वी.के. फर्नीचर
              </span>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                data-testid={link.id}
                className={`font-sans font-medium text-sm uppercase tracking-widest transition-colors duration-300 ${
                  isActive(link.path)
                    ? 'text-teak border-b-2 border-brass pb-1'
                    : 'text-stone hover:text-teak'
                }`}
              >
                {link.name}
              </Link>
            ))}
            <a
              href="tel:09821454706"
              data-testid="nav-call-btn"
              className="flex items-center gap-2 bg-teak text-cream px-5 py-2.5 hover:bg-walnut transition-all duration-300 font-sans text-xs uppercase tracking-wider font-semibold"
            >
              <Phone size={14} />
              Call Now
            </a>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              data-testid="mobile-menu-toggle"
              className="text-espresso hover:text-brass transition-colors p-2"
              aria-label="Toggle Menu"
            >
              {isOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Drawer Menu */}
      {isOpen && (
        <div className="md:hidden bg-cream border-b border-borderSubtle fade-in">
          <div className="px-2 pt-2 pb-6 space-y-3 sm:px-3 text-center flex flex-col items-center">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                data-testid={`${link.id}-mobile`}
                onClick={() => setIsOpen(false)}
                className={`block w-full py-3 font-sans font-semibold text-base uppercase tracking-widest transition-colors ${
                  isActive(link.path)
                    ? 'text-teak bg-parchment'
                    : 'text-stone hover:text-teak'
                }`}
              >
                {link.name}
              </Link>
            ))}
            <div className="pt-4 w-full px-4 flex flex-col gap-3">
              <a
                href="tel:09821454706"
                data-testid="nav-call-btn-mobile"
                className="flex items-center justify-center gap-2 bg-teak text-cream py-3 hover:bg-walnut transition-all font-sans text-sm uppercase tracking-wider font-semibold w-full"
              >
                <Phone size={16} />
                Call Now
              </a>
              <a
                href="https://wa.me/919821454706?text=Hi%20V.K.%20Furniture%2C%20I%20am%20interested%20in%20your%20wholesale%20furniture%20catalog."
                target="_blank"
                rel="noreferrer"
                data-testid="nav-whatsapp-btn-mobile"
                className="flex items-center justify-center gap-2 bg-[#25D366] text-white py-3 hover:bg-[#20ba5a] transition-all font-sans text-sm uppercase tracking-wider font-semibold w-full"
              >
                <MessageSquare size={16} />
                WhatsApp Us
              </a>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
